import{_ as e,o as a,c as l,a4 as n}from"./chunks/framework._in6GHBg.js";const p=JSON.parse('{"title":"通用格式规范","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Review-Routine-003-通用格式规范-V1.0-20260405.md","filePath":"chemistry/Chem-Review-Routine-003-通用格式规范-V1.0-20260405.md"}'),s={name:"chemistry/Chem-Review-Routine-003-通用格式规范-V1.0-20260405.md"};function i(r,t,o,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="通用格式规范" tabindex="-1">通用格式规范 <a class="header-anchor" href="#通用格式规范" aria-label="Permalink to &quot;通用格式规范&quot;">​</a></h1><p><strong>化学答题的硬性底线——格式不对，扣分很冤</strong></p><hr><h2 id="一、化学方程式书写规范" tabindex="-1">一、化学方程式书写规范 <a class="header-anchor" href="#一、化学方程式书写规范" aria-label="Permalink to &quot;一、化学方程式书写规范&quot;">​</a></h2><h3 id="必扣分项-坚决避免" tabindex="-1">必扣分项（坚决避免） <a class="header-anchor" href="#必扣分项-坚决避免" aria-label="Permalink to &quot;必扣分项（坚决避免）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">错误类型</th><th style="text-align:center;">错误示例</th><th style="text-align:center;">正确写法</th><th style="text-align:center;">扣分</th></tr></thead><tbody><tr><td style="text-align:center;">不配平</td><td style="text-align:center;">H₂ + O₂ = H₂O</td><td style="text-align:center;">2H₂ + O₂ = 2H₂O</td><td style="text-align:center;">1-2分</td></tr><tr><td style="text-align:center;">漏写条件</td><td style="text-align:center;">2KClO₃ = 2KCl + 3O₂↑</td><td style="text-align:center;">2KClO₃ =△= 2KCl + 3O₂↑</td><td style="text-align:center;">0.5-1分</td></tr><tr><td style="text-align:center;">漏写状态符号</td><td style="text-align:center;">CaCO₃ + 2HCl = CaCl₂ + H₂O + CO₂</td><td style="text-align:center;">CaCO₃ + 2HCl = CaCl₂ + H₂O + CO₂↑</td><td style="text-align:center;">0.5分</td></tr><tr><td style="text-align:center;">可逆号写错</td><td style="text-align:center;">N₂ + 3H₂ = 2NH₃</td><td style="text-align:center;">N₂ + 3H₂ ⇌ 2NH₃</td><td style="text-align:center;">0.5分</td></tr><tr><td style="text-align:center;">化学式写错</td><td style="text-align:center;">NaCO₃</td><td style="text-align:center;">Na₂CO₃</td><td style="text-align:center;">全扣</td></tr></tbody></table><h3 id="状态符号使用规则" tabindex="-1">状态符号使用规则 <a class="header-anchor" href="#状态符号使用规则" aria-label="Permalink to &quot;状态符号使用规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">符号</th><th style="text-align:left;">含义</th><th style="text-align:left;">使用场景</th></tr></thead><tbody><tr><td style="text-align:center;">↑</td><td style="text-align:left;">气体</td><td style="text-align:left;">反应物无气体，生成物有气体</td></tr><tr><td style="text-align:center;">↓</td><td style="text-align:left;">沉淀</td><td style="text-align:left;">溶液中反应生成难溶物</td></tr><tr><td style="text-align:center;">(g)</td><td style="text-align:left;">气态</td><td style="text-align:left;">热化学方程式</td></tr><tr><td style="text-align:center;">(l)</td><td style="text-align:left;">液态</td><td style="text-align:left;">热化学方程式</td></tr><tr><td style="text-align:center;">(s)</td><td style="text-align:left;">固态</td><td style="text-align:left;">热化学方程式</td></tr><tr><td style="text-align:center;">(aq)</td><td style="text-align:left;">水溶液</td><td style="text-align:left;">热化学方程式、离子方程式</td></tr></tbody></table><p><strong>注意</strong>：</p><ul><li>反应物有气体，生成物气体不标↑</li><li>热化学方程式必须注明状态</li></ul><h3 id="示例对比" tabindex="-1">示例对比 <a class="header-anchor" href="#示例对比" aria-label="Permalink to &quot;示例对比&quot;">​</a></h3><p><strong>❌ 错误写法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cu + 4HNO3 = Cu(NO3)2 + 2NO2 + 2H2O</span></span></code></pre></div><p><strong>✅ 正确写法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cu + 4HNO₃(浓) =△= Cu(NO₃)₂ + 2NO₂↑ + 2H₂O</span></span></code></pre></div><p><strong>检查清单</strong>：</p><ul><li>[ ] 配平了吗？</li><li>[ ] 反应条件写了吗？</li><li>[ ] 气体/沉淀符号标了吗？</li><li>[ ] 化学式写对了吗？</li></ul><hr><h2 id="二、离子方程式书写规范" tabindex="-1">二、离子方程式书写规范 <a class="header-anchor" href="#二、离子方程式书写规范" aria-label="Permalink to &quot;二、离子方程式书写规范&quot;">​</a></h2><h3 id="拆与不拆规则" tabindex="-1">拆与不拆规则 <a class="header-anchor" href="#拆与不拆规则" aria-label="Permalink to &quot;拆与不拆规则&quot;">​</a></h3><p><strong>必须拆（写离子）</strong>：</p><ul><li>强酸：HCl、H₂SO₄、HNO₃、HClO₄等</li><li>强碱：NaOH、KOH、Ba(OH)₂、Ca(OH)₂（澄清溶液）</li><li>可溶性盐：钠盐、钾盐、铵盐、硝酸盐等</li></ul><p><strong>不能拆（写化学式）</strong>：</p><ul><li>弱酸、弱碱、水</li><li>难溶物、单质、氧化物</li><li>气体、有机物（除少数有机酸）</li></ul><h3 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">错误</th><th style="text-align:center;">原因</th><th style="text-align:center;">正确</th></tr></thead><tbody><tr><td style="text-align:center;">CH₃COOH = CH₃COO⁻ + H⁺</td><td style="text-align:center;">弱酸不拆</td><td style="text-align:center;">CH₃COOH ⇌ CH₃COO⁻ + H⁺</td></tr><tr><td style="text-align:center;">CaCO₃ = Ca²⁺ + CO₃²⁻</td><td style="text-align:center;">难溶物不拆</td><td style="text-align:center;">CaCO₃（保留化学式）</td></tr><tr><td style="text-align:center;">NH₃·H₂O = NH₄⁺ + OH⁻</td><td style="text-align:center;">弱碱不拆</td><td style="text-align:center;">NH₃·H₂O ⇌ NH₄⁺ + OH⁻</td></tr></tbody></table><h3 id="检查清单" tabindex="-1">检查清单 <a class="header-anchor" href="#检查清单" aria-label="Permalink to &quot;检查清单&quot;">​</a></h3><ul><li>[ ] 强酸强碱可溶性盐拆了吗？</li><li>[ ] 弱酸弱碱难溶物没拆吗？</li><li>[ ] 原子守恒吗？</li><li>[ ] 电荷守恒吗？</li></ul><hr><h2 id="三、热化学方程式规范" tabindex="-1">三、热化学方程式规范 <a class="header-anchor" href="#三、热化学方程式规范" aria-label="Permalink to &quot;三、热化学方程式规范&quot;">​</a></h2><h3 id="必写要素" tabindex="-1">必写要素 <a class="header-anchor" href="#必写要素" aria-label="Permalink to &quot;必写要素&quot;">​</a></h3><ol><li><strong>注明物质状态</strong>：(g)、(l)、(s)、(aq)</li><li><strong>注明ΔH</strong>：+ 吸热，- 放热</li><li><strong>单位</strong>：kJ/mol</li><li><strong>化学计量数与ΔH对应</strong></li></ol><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H₂(g) + ½O₂(g) = H₂O(l)  ΔH = -285.8 kJ/mol</span></span>
<span class="line"><span>2H₂(g) + O₂(g) = 2H₂O(l)  ΔH = -571.6 kJ/mol</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>ΔH与化学计量数成正比</li><li>逆反应的ΔH符号相反</li></ul><hr><h2 id="四、电极反应式规范" tabindex="-1">四、电极反应式规范 <a class="header-anchor" href="#四、电极反应式规范" aria-label="Permalink to &quot;四、电极反应式规范&quot;">​</a></h2><h3 id="书写步骤" tabindex="-1">书写步骤 <a class="header-anchor" href="#书写步骤" aria-label="Permalink to &quot;书写步骤&quot;">​</a></h3><ol><li><strong>确定电极</strong>：阳极/阴极（或正极/负极）</li><li><strong>确定反应物</strong>：电极材料或溶液中离子</li><li><strong>写出产物</strong></li><li><strong>配平</strong>： <ul><li>原子守恒（先用H₂O、H⁺、OH⁻配平）</li><li>电荷守恒（用e⁻配平）</li></ul></li></ol><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>电解NaCl溶液</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阳极：2Cl⁻ - 2e⁻ = Cl₂↑</span></span>
<span class="line"><span>阴极：2H⁺ + 2e⁻ = H₂↑  （或 2H₂O + 2e⁻ = H₂↑ + 2OH⁻）</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>酸性溶液用H⁺配平</li><li>碱性溶液用OH⁻配平</li><li>必须注明电子得失（- 失电子，+ 得电子）</li></ul><hr><h2 id="五、计算题规范" tabindex="-1">五、计算题规范 <a class="header-anchor" href="#五、计算题规范" aria-label="Permalink to &quot;五、计算题规范&quot;">​</a></h2><h3 id="步骤分很重要" tabindex="-1">步骤分很重要 <a class="header-anchor" href="#步骤分很重要" aria-label="Permalink to &quot;步骤分很重要&quot;">​</a></h3><p><strong>❌ 错误示范</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>9 g水的物质的量是0.5 mol</span></span></code></pre></div><p><strong>✅ 正确示范</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：</span></span>
<span class="line"><span>M(H₂O) = 18 g/mol</span></span>
<span class="line"><span>n(H₂O) = m/M = 9 g / 18 g/mol = 0.5 mol</span></span>
<span class="line"><span>答：9 g水的物质的量是0.5 mol</span></span></code></pre></div><h3 id="必须写出的要素" tabindex="-1">必须写出的要素 <a class="header-anchor" href="#必须写出的要素" aria-label="Permalink to &quot;必须写出的要素&quot;">​</a></h3><ol><li><strong>已知条件</strong></li><li><strong>所用公式</strong></li><li><strong>代入数据</strong>（带单位）</li><li><strong>计算结果</strong>（带单位）</li><li><strong>答</strong>（完整回答）</li></ol><h3 id="有效数字" tabindex="-1">有效数字 <a class="header-anchor" href="#有效数字" aria-label="Permalink to &quot;有效数字&quot;">​</a></h3><ul><li>一般保留2-3位有效数字</li><li>题目有要求按题目要求</li><li>不要无限位小数（如0.500000000）</li></ul><hr><h2 id="六、简答题规范" tabindex="-1">六、简答题规范 <a class="header-anchor" href="#六、简答题规范" aria-label="Permalink to &quot;六、简答题规范&quot;">​</a></h2><h3 id="答题模板" tabindex="-1">答题模板 <a class="header-anchor" href="#答题模板" aria-label="Permalink to &quot;答题模板&quot;">​</a></h3><p><strong>问：为什么...？</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>答：因为...（原理），导致...（结果），所以...（结论）</span></span></code></pre></div><p><strong>问：有什么现象？</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>答：...（颜色变化），...（沉淀/气体），...（温度变化）</span></span></code></pre></div><p><strong>问：如何操作？</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>答：第一步：...；第二步：...；第三步：...（分点作答）</span></span></code></pre></div><h3 id="示例-2" tabindex="-1">示例 <a class="header-anchor" href="#示例-2" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>问：为什么收集氨气要用向下排空气法？</strong></p><p><strong>❌ 错误答法</strong>：因为氨气密度小。</p><p><strong>✅ 正确答法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>答：因为NH₃的相对分子质量为17，小于空气的平均相对分子质量29，</span></span>
<span class="line"><span>    所以NH₃密度小于空气，且NH₃极易溶于水，不能用排水法收集，</span></span>
<span class="line"><span>    故采用向下排空气法收集。</span></span></code></pre></div><hr><h2 id="七、实验题规范" tabindex="-1">七、实验题规范 <a class="header-anchor" href="#七、实验题规范" aria-label="Permalink to &quot;七、实验题规范&quot;">​</a></h2><h3 id="现象描述要点" tabindex="-1">现象描述要点 <a class="header-anchor" href="#现象描述要点" aria-label="Permalink to &quot;现象描述要点&quot;">​</a></h3><p><strong>必须包含</strong>：</p><ol><li><strong>视觉</strong>：颜色变化、沉淀生成、气体产生</li><li><strong>听觉</strong>：声音（如爆鸣声）</li><li><strong>嗅觉</strong>：气味（题目要求时）</li><li><strong>触觉</strong>：温度变化（放热/吸热）</li></ol><h3 id="示例-3" tabindex="-1">示例 <a class="header-anchor" href="#示例-3" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>钠与水反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现象：钠浮在水面上（浮），熔成闪亮的小球（熔），</span></span>
<span class="line"><span>      四处游动（游），发出嘶嘶的响声（响），</span></span>
<span class="line"><span>      溶液变红（加酚酞后）（红）</span></span></code></pre></div><h3 id="操作描述要点" tabindex="-1">操作描述要点 <a class="header-anchor" href="#操作描述要点" aria-label="Permalink to &quot;操作描述要点&quot;">​</a></h3><ul><li>用药匙取用固体</li><li>用镊子取用块状固体</li><li>滴管垂直悬空，不伸入容器</li><li>倾倒液体时标签向手心</li></ul><hr><h2 id="八、易错格式汇总" tabindex="-1">八、易错格式汇总 <a class="header-anchor" href="#八、易错格式汇总" aria-label="Permalink to &quot;八、易错格式汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:center;">常见错误</th><th style="text-align:center;">正确格式</th></tr></thead><tbody><tr><td style="text-align:left;">离子方程式</td><td style="text-align:center;">Ag⁺ + Cl⁻ = AgCl</td><td style="text-align:center;">Ag⁺ + Cl⁻ = AgCl↓</td></tr><tr><td style="text-align:left;">热化学方程式</td><td style="text-align:center;">H₂ + O₂ = H₂O ΔH=-286kJ/mol</td><td style="text-align:center;">H₂(g)+½O₂(g)=H₂O(l) ΔH=-286 kJ/mol</td></tr><tr><td style="text-align:left;">电极反应</td><td style="text-align:center;">Cl⁻ = Cl₂ + e⁻</td><td style="text-align:center;">2Cl⁻ - 2e⁻ = Cl₂↑</td></tr><tr><td style="text-align:left;">计算题</td><td style="text-align:center;">0.5mol</td><td style="text-align:center;">n = 0.5 mol（带公式和过程）</td></tr><tr><td style="text-align:left;">简答题</td><td style="text-align:center;">&quot;因为密度小&quot;</td><td style="text-align:center;">&quot;因为NH₃相对分子质量(17)小于空气(29)，密度小于空气&quot;</td></tr></tbody></table><hr><h2 id="九、检查清单-考前必读" tabindex="-1">九、检查清单（考前必读） <a class="header-anchor" href="#九、检查清单-考前必读" aria-label="Permalink to &quot;九、检查清单（考前必读）&quot;">​</a></h2><h3 id="方程式检查" tabindex="-1">方程式检查 <a class="header-anchor" href="#方程式检查" aria-label="Permalink to &quot;方程式检查&quot;">​</a></h3><ul><li>[ ] 配平了吗？</li><li>[ ] 条件写了吗？（△、催化剂、点燃等）</li><li>[ ] 状态符号标了吗？（↑、↓、(g)、(l)等）</li><li>[ ] 可逆号/等号用对了吗？</li></ul><h3 id="计算题检查" tabindex="-1">计算题检查 <a class="header-anchor" href="#计算题检查" aria-label="Permalink to &quot;计算题检查&quot;">​</a></h3><ul><li>[ ] 公式写了吗？</li><li>[ ] 单位带了吗？</li><li>[ ] 有效数字对吗？</li><li>[ ] 答写了吗？</li></ul><h3 id="简答题检查" tabindex="-1">简答题检查 <a class="header-anchor" href="#简答题检查" aria-label="Permalink to &quot;简答题检查&quot;">​</a></h3><ul><li>[ ] 原理说明了吗？</li><li>[ ] 逻辑清晰吗？</li><li>[ ] 分点作答了吗？（如果问&quot;有哪些原因&quot;）</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Review-Routine-003<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>用途</strong>: 答题格式硬性规范<br><strong>配套文档</strong>: 所有化学试卷</p><hr><p><em>格式不对，答案全废。宁可慢一点，也要规范。</em></p>`,96)])])}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
